import type { HeadFC, PageProps } from "gatsby";
import * as React from "react";

import { Box, Checkbox, Divider, FormControlLabel, FormGroup, Grid, Pagination, Slider, Typography } from "@mui/material";
import { useTheme } from '@mui/material/styles';
import useMediaQuery from '@mui/material/useMediaQuery';
import Layout from "../components/Layout";
import Product from "../components/Product";
import {
    CardStyled,
    PaginationContainer
} from "../components/productsStyles";
import { formatMoney } from "../utils/utils";
import useSettings from "../storage/useSettings";

const products = [
    {
        id: 1,
        name: 'Teste 1',
        price: 2000,
        oldPrice: 3000
    },
    {
        id: 2,
        name: 'Teste 2',
        price: 2000,
        oldPrice: 3000
    },
    {
        id: 3,
        name: 'Teste 3',
        price: 2000,
        oldPrice: 3000
    },
    {
        id: 4,
        name: 'Teste 4',
        price: 2000,
        oldPrice: 3000
    },
    {
        id: 5,
        name: 'Teste 5',
        price: 2000,
        oldPrice: 3000
    },
]
const IndexPage: React.FC<PageProps> = () => {
    const theme = useTheme();
    const isLargeScreen = useMediaQuery(theme.breakpoints.up('lg'));

    // State variables for checkboxes
    const [isMaleChecked, setMaleChecked] = React.useState(false);
    const [isFemaleChecked, setFemaleChecked] = React.useState(false);
    const [filterPrice, setFilterPrice] = React.useState<number[]>([0, 10000]);
    const handleFilterPrice = (event: Event, newValue: number | number[]) => {
        setFilterPrice(newValue as number[]);
    };

    function filterPriceValuetext(value: number) {
        return formatMoney(value);
      }

    return (
        <Layout>
            <Grid container spacing={2}>
                {isLargeScreen &&
                    <Grid item lg={2}>
                        <Box>
                            <Typography variant="h6" gutterBottom>
                                Gênero
                            </Typography>
                            <FormGroup>
                                <FormControlLabel
                                    control={<Checkbox checked={isMaleChecked} onChange={() => setMaleChecked(!isMaleChecked)} />}
                                    label="Masculino"
                                />
                                <FormControlLabel
                                    control={<Checkbox checked={isFemaleChecked} onChange={() => setFemaleChecked(!isFemaleChecked)} />}
                                    label="Feminino"
                                />
                            </FormGroup>
                        </Box>
                        <Divider />
                        <Box sx={{ width: '60%' }}>
                            <Typography variant="h6" gutterBottom>
                                Preço
                            </Typography>
                            <Slider
                                getAriaLabel={() => 'Preço'}
                                value={filterPrice}
                                onChange={handleFilterPrice}
                                valueLabelDisplay="auto"
                                min={1000}
                                max={10000}
                                valueLabelFormat={filterPriceValuetext}
                                getAriaValueText={filterPriceValuetext}
                            />
                            <Typography variant="body1" gutterBottom>
                                {formatMoney(filterPrice[0]) + ' - ' + formatMoney(filterPrice[1])}
                            </Typography>
                        </Box>
                    </Grid>
                }
                <Grid item lg={10}>
                    <Grid container spacing={2}
                        bgcolor={'black'}>
                        {products.map((product) => (
                            <Grid key={product.id} item xs={12} sm={12} md={6} lg={4} xl={3} style={{ display: 'flex', justifyContent: 'center' }}>
                                <CardStyled>
                                    <Product product={product} onClick={() => console.log('clicou')} />
                                </CardStyled>
                            </Grid>
                        ))}
                    </Grid>

                    <PaginationContainer>
                        <Pagination
                            count={5}
                            color="primary"
                            page={1}
                        // onChange={(e, page) => setCurrentPage(page)}
                        />
                    </PaginationContainer>
                </Grid>
            </Grid>
        </Layout>
    );
}

export default IndexPage;

export const Head: HeadFC = () => <title>Home Page</title>
